// Get all items from Merge
const allItems = $input.all();

// Extract data from first item
const extractItem = allItems[0]?.json || {};
const financials = extractItem.data || extractItem;

// Analysis from second item
const analysisItem = allItems[1]?.json || {};
const analysis = analysisItem.markdown || analysisItem.answer || analysisItem.text || 'No analysis generated';

// Get trigger data
const triggerData = $('New Statement').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Income statement
const is = financials.incomeStatement || {};
const revenue = is.revenue || 0;
const grossProfit = is.grossProfit || 0;
const grossMargin = is.grossMargin || (revenue > 0 ? (grossProfit / revenue * 100).toFixed(1) : 0);
const ebitda = is.ebitda || 0;
const netIncome = is.netIncome || 0;
const netMargin = revenue > 0 ? (netIncome / revenue * 100).toFixed(1) : 0;

// Balance sheet
const bs = financials.balanceSheet || {};
const totalAssets = bs.totalAssets || 0;
const totalLiabilities = bs.totalLiabilities || 0;
const totalEquity = bs.totalEquity || 0;
const currentAssets = bs.currentAssets || 0;
const currentLiabilities = bs.currentLiabilities || 0;
const totalDebt = bs.totalDebt || 0;
const cash = bs.cashAndEquivalents || 0;

// Calculate ratios
const currentRatio = currentLiabilities > 0 ? (currentAssets / currentLiabilities).toFixed(2) : 'N/A';
const debtToEquity = totalEquity > 0 ? (totalDebt / totalEquity).toFixed(2) : 'N/A';
const debtToAssets = totalAssets > 0 ? (totalDebt / totalAssets * 100).toFixed(1) : 'N/A';

// Cash flow
const cf = financials.cashFlow || {};
const operatingCF = cf.operatingCashFlow || 0;
const freeCashFlow = cf.freeCashFlow || 0;

// Prior period comparison
const prior = financials.priorPeriod || {};
const priorRevenue = prior.revenue || 0;
const yoyGrowth = priorRevenue > 0 ? ((revenue - priorRevenue) / priorRevenue * 100).toFixed(1) : 'N/A';

// Risk flags
let riskFlags = [];
if (parseFloat(currentRatio) < 1) riskFlags.push('Low liquidity');
if (parseFloat(debtToEquity) > 2) riskFlags.push('High leverage');
if (netIncome < 0) riskFlags.push('Net loss');
if (operatingCF < 0) riskFlags.push('Negative operating cash flow');
if (parseFloat(yoyGrowth) < -10) riskFlags.push('Revenue decline >10%');

// Health score estimation
let healthScore = 70;
if (riskFlags.length === 0) healthScore = 85;
if (riskFlags.length >= 2) healthScore = 55;
if (riskFlags.length >= 3) healthScore = 40;

// Format large numbers
function formatMoney(num) {
  if (Math.abs(num) >= 1e9) return (num / 1e9).toFixed(1) + 'B';
  if (Math.abs(num) >= 1e6) return (num / 1e6).toFixed(1) + 'M';
  if (Math.abs(num) >= 1e3) return (num / 1e3).toFixed(1) + 'K';
  return num.toString();
}

return [{
  json: {
    companyName: financials.companyName || 'Unknown',
    fiscalPeriodEnd: financials.fiscalPeriodEnd || 'N/A',
    reportType: financials.reportType || 'N/A',
    currency: financials.currency || 'USD',
    revenue: revenue,
    revenueFormatted: formatMoney(revenue),
    grossProfit: grossProfit,
    grossMargin: grossMargin + '%',
    ebitda: ebitda,
    ebitdaFormatted: formatMoney(ebitda),
    netIncome: netIncome,
    netIncomeFormatted: formatMoney(netIncome),
    netMargin: netMargin + '%',
    totalAssets: totalAssets,
    totalAssetsFormatted: formatMoney(totalAssets),
    totalLiabilities: totalLiabilities,
    totalEquity: totalEquity,
    totalDebt: totalDebt,
    totalDebtFormatted: formatMoney(totalDebt),
    cash: cash,
    cashFormatted: formatMoney(cash),
    currentRatio: currentRatio,
    debtToEquity: debtToEquity,
    debtToAssets: debtToAssets + '%',
    operatingCashFlow: operatingCF,
    freeCashFlow: freeCashFlow,
    yoyGrowth: yoyGrowth + '%',
    riskFlags: riskFlags.join('; ') || 'None',
    riskFlagCount: riskFlags.length,
    healthScore: healthScore,
    analysis: analysis,
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

